import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for handling if-else statements with empty THEN blocks
 * Regression test for NPE issue when processing code like: else if (condition) else { }
 */
class MultiLineIfElseRuleEmptyThenBlockTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Given an if-else-if statement with empty THEN block in the second if`() {
        val code =
            """
            fun foo() {
                if ("a" == "b") {
                } else if ("b" == "c") else {
                }
            }
            """.trimIndent()
        // This code should not crash ktlint, even though it's unusual Kotlin code
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an if statement with empty THEN block followed by else`() {
        val code =
            """
            fun foo() {
                if (true) else {
                    println("else")
                }
            }
            """.trimIndent()
        // This code should not crash ktlint
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a complex nested if-else with empty THEN block`() {
        val code =
            """
            fun foo() {
                if (a) {
                    doSomething()
                } else if (b) else if (c) {
                    doSomethingElse()
                } else {
                    doDefault()
                }
            }
            """.trimIndent()
        // This code should not crash ktlint
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

